int s[1 << 12][N];
int find(const int st, int x) {
	if (s[st][x] == x)return x;
	return s[st][x] = find(st, s[st][x]);
}
void solve(int CASE)
{
	int n, q; cin >> n >> q;
	fa(mask, 0, (1 << 12) - 1)fa(i, 1, n)s[mask][i] = i;

	ll ans = 0;
	while (q--) {
		char op; cin >> op;
		if (op == '+') {
			int u, v, w; cin >> u >> v >> w;
			var dfs = [&](var dfs, int sub)->void {
				// 处理子集 sub
				int e1 = find(sub, u);
				int e2 = find(sub, v);
				if (e1 == e2)return;
				s[sub][e2] = e1;

				fa(k, 0, 11)
					if (sub & (1 << k))
						dfs(dfs, sub ^ (1 << k));
				};
			dfs(dfs, w);
		}
		else {
			int x, y; cin >> x >> y;
			int now = 0;
			fb(k, 11, 0) {
				int e1 = find(now | (1 << k), x);
				int e2 = find(now | (1 << k), y);
				if (e1 == e2)now |= 1 << k;
			}
			if (now == 0) {
				int e1 = find(now, x);
				int e2 = find(now, y);
				if (e1 == e2)ans += 0;
				else ans += -1;
			}
			else ans += now;
		}
	}
	cout << ans << endl;
	return;
}
